import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.D5wUhsuj.js";const r="/docs/assets/custom-image-spawner.0_pMsG5R.png",i="/docs/assets/registry-credentials-ui.Dr_V2aw-.png",b=JSON.parse('{"title":"Custom Notebooks","description":"","frontmatter":{},"headers":[],"relativePath":"labs/custom_notebooks.md","filePath":"labs/custom_notebooks.md","lastUpdated":1783543014000}'),n={name:"labs/custom_notebooks.md"};function l(c,e,m,d,p,u){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="custom-notebooks" tabindex="-1">Custom Notebooks <a class="header-anchor" href="#custom-notebooks" aria-label="Permalink to &quot;Custom Notebooks&quot;">​</a></h1><p>Custom Notebooks let you run specialized Lab environments when the standard JupyterLab, VS Code, RStudio, or OpenCode images are not enough.</p><p>Use a custom notebook image when you need a controlled package stack, additional system tools, GPU-specific libraries, or a web application that should run inside the same workspace boundary as the rest of your prokube work.</p><h2 id="common-uses" tabindex="-1">Common Uses <a class="header-anchor" href="#common-uses" aria-label="Permalink to &quot;Common Uses&quot;">​</a></h2><ul><li>Preinstall Python, R, CUDA, or system packages that should be available every time the Lab starts.</li><li>Package team-specific tooling, CLIs, SDKs, or templates into a reusable image.</li><li>Run a custom browser-based web server for rapid prototyping.</li><li>Test specialized development environments before turning them into shared images.</li></ul><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Custom Notebooks use the same technical foundation as other Labs: a <a href="https://www.kubeflow.org/docs/components/notebooks/" target="_blank" rel="noreferrer">Kubeflow Notebook</a> pod with configurable compute resources, persistent workspace storage, optional data volumes, and workspace-level configuration.</p><p><img src="'+r+'" alt="Launch a custom notebook image" loading="lazy"></p><p>At minimum, you need to:</p><ol><li>Build a container image that is compatible with <a href="https://www.kubeflow.org/docs/components/notebooks/container-images/#custom-images" target="_blank" rel="noreferrer">Kubeflow custom notebook images</a>.</li><li>Push the image to a container registry that the Kubernetes cluster can reach.</li><li>Add registry credentials if the image is private and no matching registry pull secret has already been configured by an administrator.</li><li>Select the image in the Custom Notebook launch dialog.</li></ol><p>For custom web applications, the container should expose the expected notebook port and handle being served behind the platform&#39;s notebook proxy path.</p><p>Use <a href="./">Using Labs</a> for the shared workspace, persistence, object-storage, and image-building behavior. Use custom images when user-space package installation is not enough or when a team needs the same environment repeatedly.</p><p>The <a href="https://github.com/prokube/examples/tree/main/images/streamlit-example" target="_blank" rel="noreferrer"><code>prokube/examples</code> Streamlit example</a> shows a custom image that can run as a Kubeflow Notebook and serve a Streamlit app behind the notebook proxy path.</p><h2 id="registry-credentials" tabindex="-1">Registry Credentials <a class="header-anchor" href="#registry-credentials" aria-label="Permalink to &quot;Registry Credentials&quot;">​</a></h2><p>If your custom image is stored in a private registry, the workspace needs an image pull secret before Kubernetes can start the Lab pod. This may already be handled globally by an administrator, for example through a shared <code>regcred-*</code> secret. If not, add registry credentials for the workspace.</p><p>In the prokube UI, click your user icon in the top-right corner and open the registry credentials action. Use it to configure the registry server, username, and token or password for the workspace.</p><p><img src="'+i+'" alt="Registry credentials" loading="lazy"></p><p>Registry credentials are stored as Kubernetes <code>Secret</code>s in the workspace. Edit and view contributors of that workspace can read Kubernetes <code>Secret</code>s in the namespace, so use registry credentials intended for that workspace rather than personal or admin credentials.</p><p>For the Kubernetes-level behavior of image pull credentials, see <a href="./../platform/kubernetes.html#registry-credentials">Registry Credentials</a>.</p><h2 id="custom-solutions" tabindex="-1">Custom Solutions <a class="header-anchor" href="#custom-solutions" aria-label="Permalink to &quot;Custom Solutions&quot;">​</a></h2><p>prokube can support custom Lab solutions for teams that need specialized images, custom web applications, GPU stacks, or additional platform integration.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./">Using Labs</a></li><li><a href="./jupyterlab.html">JupyterLab</a></li><li><a href="./rstudio.html">RStudio</a></li><li><a href="https://github.com/prokube/examples/tree/main/images/streamlit-example" target="_blank" rel="noreferrer">Streamlit custom image example</a></li><li><a href="https://www.kubeflow.org/docs/components/notebooks/container-images/#custom-images" target="_blank" rel="noreferrer">Kubeflow custom image documentation</a></li></ul>',23)])])}const g=t(n,[["render",l]]);export{b as __pageData,g as default};
